    return re.sub(r'^#', '', str(id_str).strip())

# Clean all IDs in cases data
cleaned_cases = []
for case in cases_data:
    cleaned_case = {}
    for key, value in case.items():
        if key in ['id', 'ownerid', 'contactid', 'accountid']:
            cleaned_case[key] = clean_id(value)
        elif key == 'status':
            cleaned_case[key] = value.strip() if value else None
        else:
            cleaned_case[key] = value
    cleaned_cases.append(cleaned_case)

